// ResourceServiceMCPDefaultBasePath is the default HTTP path prefix for
// ResourceService MCP endpoints, derived from the protobuf package and service name.
const ResourceServiceMCPDefaultBasePath = "/freebusy/resource/v1/resourceservice/mcp"

// ResourceServiceCompletionMap returns a map of "promptName:argName" → allowed
// values, built from enum_values declared in the proto MCP options.
func ResourceServiceCompletionMap() map[string][]string {
	m := map[string][]string{}
	m["add_resource:booking_mode"] = []string{"time_slot", "nightly"}
	return m
}

// ServeResourceServiceMCP creates an MCP server, registers the service tools, and
// starts serving using the configured transport (streamable-http, sse, or stdio).
// Uses the proto-derived BasePath. This is a blocking call.
func ServeResourceServiceMCP(ctx context.Context, srv ResourceServiceMCPServer, cfg *runtime.MCPServerConfig, opts ...runtime.Option) error {
	// Set the proto-derived path as the generated default
	cfg.GeneratedBasePath = ResourceServiceMCPDefaultBasePath

	// Wire completion handler for prompt arguments with enum_values.
	completionMap := ResourceServiceCompletionMap()
	if len(completionMap) > 0 {
		if cfg.ServerOptions == nil {
			cfg.ServerOptions = &mcp.ServerOptions{}
		}
		cfg.ServerOptions.CompletionHandler = runtime.CompletionHandlerFromEnums(completionMap)
	}

	return runtime.StartServer(ctx, cfg, func(s *mcp.Server) {
		RegisterResourceServiceMCPHandler(s, srv, opts...)
	})
}

